50	void Opencore::CreateCorePrStatus(int pid) {
51	    if (!threads.size()) return;
52	
53	    prstatus.assign(threads.size(), {});
54	    int prnum = (int)prstatus.size();
55	
56	    int cur = 1;
57	    for (int index = 0; index < prnum; index++) {
58	        pid_t tid = threads[index].pid;
59	        int idx;
60	        if (tid == getTid()) {
61	            idx = 0;
62	            prstatus[idx].pr_pid = tid;
63	            // top thread maybe use ucontext prs
64	            if (getContext()) {
65	                struct ucontext *context = (struct ucontext *) getContext();
66	                memcpy(&prstatus[idx].pr_reg, &context->uc_mcontext.regs, sizeof(arm64::pt_regs));
67	                continue;
68	            }
69	        } else {
70	            // 0 top thread was truncated
71	            idx = (cur >= prnum) ? 0 : cur;
72	            ++cur;
73	            prstatus[idx].pr_pid = tid;
74	        }
75	
76	        struct iovec ioVec = {
77	            &prstatus[idx].pr_reg,
78	            sizeof(arm64::pt_regs),
79	        };
80	
81	        if (ptrace(PTRACE_GETREGSET, tid, NT_PRSTATUS, &ioVec) < 0)
82	            continue;
83	    }
84	
85	    extra_note_filesz += (sizeof(Elf64_prstatus) + sizeof(Elf64_Nhdr) + 8) * prnum; // NT_PRSTATUS
86	    extra_note_filesz += sizeof(siginfo_t) + sizeof(Elf64_Nhdr) + 8;      // NT_SIGINFO
87	    extra_note_filesz += (sizeof(Elf64_fpregset) + sizeof(Elf64_Nhdr) + 8) * prnum; // NT_FPREGSET
88	    extra_note_filesz += (sizeof(Elf64_tls) + sizeof(Elf64_Nhdr) + 8) * prnum; // NT_ARM_TLS
89	    extra_note_filesz += ((sizeof(struct user_pac_mask) + sizeof(Elf64_Nhdr) + 8)  // NT_ARM_PAC_MASK
90	                      + (sizeof(uint64_t) + sizeof(Elf64_Nhdr) + 8)       // NT_ARM_PAC_ENABLED_KEYS
91	                      ) * prnum;
92	    extra_note_filesz += (sizeof(uint64_t) + sizeof(Elf64_Nhdr) + 8) * prnum;  // NT_ARM_TAGGED_ADDR_CTRL
93	}
